**Step 3: Create the Node.js Server**
--------------------------------------

Create a Node.js file called `server.js` and add the following code:

```javascript
const express = require('express');
const app = express();

app.use(express.json());

app.post('/submit', (req, res) => {
    const { username, email, message } = req.body;

    const fs = require('fs');
    const data = `${username} - ${email} - ${message}\n`;
    fs.appendFile('data.txt', data, (err) => {
        if (err) {
            console.error(err);
            res.status(500).send({ message: 'Error storing data' });
        } else {
            res.send({ message: 'Data stored successfully' });
        }
    });
});

app.listen(3000, () => {
    console.log('Server listening on port 3000');
});
```

